/* ── SUBSCRIPTION UTILITIES ── */
const FREE_RECIPE_LIMIT = 20;
const FREE_SAVE_LIMIT = 5;
const FREE_AUTOPLAN_USES = 1;
// ⚠️  Replace these placeholder URLs with your real Stripe payment links
const STRIPE_MONTHLY_URL = "https://buy.stripe.com/REPLACE_MONTHLY_LINK";
const STRIPE_YEARLY_URL  = "https://buy.stripe.com/REPLACE_YEARLY_LINK";

function getSubData(email) {
  // 🔧 DEV MODE: always return premium. Remove the early return to re-enable gating.
  if (!email) return { isPremium: true, autoplanUsed: 0 };
  try {
    const stored = JSON.parse(localStorage.getItem("sc_" + email.toLowerCase() + "_sub") || 'null');
    // DEV: override isPremium to true regardless of stored value
    return { ...(stored || {}), isPremium: true, autoplanUsed: stored?.autoplanUsed || 0 };
  }
  catch { return { isPremium: true, autoplanUsed: 0 }; }
}
function saveSubData(email, data) {
  if (!email) return;
  localStorage.setItem("sc_" + email.toLowerCase() + "_sub", JSON.stringify(data));
}

/* ── FAVORITES / FOLDERS / USER RECIPES ── */
const DEFAULT_FOLDERS = [
  { id:"fold_all",       name:"All Favorites", emoji:"⭐", system:true },
  { id:"fold_myrecipes", name:"My Recipes",    emoji:"📝", system:true },
  { id:"fold_bkf",       name:"Breakfast",     emoji:"🌅", system:true },
  { id:"fold_lun",       name:"Lunch",         emoji:"🥗", system:true },
  { id:"fold_din",       name:"Dinner",        emoji:"🍽️", system:true },
  { id:"fold_snk",       name:"Snacks",        emoji:"🍿", system:true },
  { id:"fold_des",       name:"Desserts",      emoji:"🍰", system:true },
];

function mergeSystemFolders(stored) {
  // Ensure any new system folders added to DEFAULT_FOLDERS are always present
  // (handles migration when new system folders are added after a user already has saved data)
  const storedIds = new Set(stored.map(f => f.id));
  const missing = DEFAULT_FOLDERS.filter(f => !storedIds.has(f.id));
  if (missing.length === 0) return stored;
  // Insert each missing folder at its natural position from DEFAULT_FOLDERS
  const result = [...stored];
  for (const mf of missing) {
    const idx = DEFAULT_FOLDERS.findIndex(df => df.id === mf.id);
    result.splice(Math.min(idx, result.length), 0, mf);
  }
  return result;
}

function getFavData(email) {
  if (!email) return { folders: DEFAULT_FOLDERS, items: [], userRecipes: [] };
  try {
    const uid = email.toLowerCase();
    const stored      = JSON.parse(localStorage.getItem(`sc_${uid}_fav_folders`)  || "null");
    const folders     = stored ? mergeSystemFolders(stored) : DEFAULT_FOLDERS;
    const items       = JSON.parse(localStorage.getItem(`sc_${uid}_fav_items`)    || "[]");
    const userRecipes = JSON.parse(localStorage.getItem(`sc_${uid}_user_recipes`) || "[]");
    return { folders, items, userRecipes };
  } catch { return { folders: DEFAULT_FOLDERS, items: [], userRecipes: [] }; }
}
function saveFavFolders(email, data)  { if (email) localStorage.setItem(`sc_${email.toLowerCase()}_fav_folders`,  JSON.stringify(data)); }
function saveFavItems(email, data)    { if (email) localStorage.setItem(`sc_${email.toLowerCase()}_fav_items`,    JSON.stringify(data)); }
function saveUserRecipes(email, data) { if (email) localStorage.setItem(`sc_${email.toLowerCase()}_user_recipes`, JSON.stringify(data)); }

