// Family groups: if a recipe asks for the family HEAD, any MEMBER in pantry counts as a match
// (but NOT vice versa — if recipe asks for "parmesan", generic "cheese" doesn't satisfy it)
const INGREDIENT_FAMILIES = {
  'cheese':    ['parmesan','mozzarella','cheddar','feta','gouda','brie','ricotta','gruyere','emmental','halloumi','paneer','goat cheese','cream cheese','cottage cheese','swiss cheese','cheese'],
  'stock':     ['stock','broth'],
  'pasta':     ['pasta','spaghetti','penne','rigatoni','fettuccine','linguine','fusilli','tagliatelle','bucatini','farfalle','orzo'],
  'oil':       ['oil','olive oil','coconut oil','sesame oil'],
  'flour':     ['flour','self-raising flour'],
  'milk':      ['milk','oat milk','almond milk','soy milk'],
  'cream':     ['cream','sour cream'],
  'onion':     ['onion','shallot'],
  'tomato':    ['tomato','sun-dried tomato'],
  'mushroom':  ['mushroom'],
  'sugar':     ['sugar'],
  'vinegar':   ['vinegar'],
  'mustard':   ['mustard'],
  'egg':       ['egg'],
  'bean':      ['chickpea','black bean','kidney bean','cannellini bean','butter bean','lentil','edamame'],
  'herb':      ['parsley','basil','cilantro','mint','dill','chives','oregano','thyme','rosemary','sage'],
  'nut':       ['almond','walnut','cashew','pine nut','peanut','nut butter','peanut butter'],
};

// THE single normalizer used everywhere in the app
function normalizeIng(name) {
  if (!name) return '';
  let n = name.toLowerCase().trim().replace(/[.,!?()\[\]]/g, '');

  // Strip prep/size words (careful not to strip meaningful words)
  n = n.replace(/\b(fresh|dried|ground|chopped|diced|sliced|minced|grated|shredded|frozen|cooked|raw|ripe|large|small|medium|whole|halved|crushed|peeled|deseeded|softened|melted|unsalted|salted|extra|pure|organic|flat-leaf|flat leaf|baby|boneless|skinless|skin-on|bone-in|thick|thin|fine|coarse|roughly|finely|thinly|thickly)\b/g, '').trim();

  // Apply synonym rules in order
  for (const [pattern, replacement] of INGREDIENT_SYNONYMS) {
    if (typeof replacement === 'function') {
      n = n.replace(pattern, replacement);
    } else {
      n = n.replace(pattern, replacement);
    }
  }

  // Collapse spaces left from stripping
  n = n.replace(/\s+/g, ' ').trim();
  return n;
}

// Checks if a recipe ingredient is satisfied by the current pantry.
// Handles both exact normalized match and "family head" matching.
function ingInPantry(recipeIngName, normalizedPantrySet) {
  const norm = normalizeIng(recipeIngName);
  if (!norm) return false;
  // 1. Exact normalized match
  if (normalizedPantrySet.has(norm)) return true;
  // 2. Family match: if recipe asks for a generic family head (e.g. "cheese"),
  //    check whether pantry has any specific member of that family.
  const members = INGREDIENT_FAMILIES[norm];
  if (members) {
    return members.some(m => normalizedPantrySet.has(m));
  }
  return false;
}

// Build a Set of normalized pantry ingredient names (call once per operation)
function buildPantrySet(pantry) {
  return new Set(pantry.map(p => normalizeIng(p.name)));
}

// ═══════════════════════════════════════════════════════════════════════
// PANTRY INTELLIGENCE ENGINE
// Centralised coverage logic — used by ALL pantry intelligence features.
// Relies on the shared normalizeIng / ingInPantry / buildPantrySet above.
// ═══════════════════════════════════════════════════════════════════════

// computeAllCoverage: score every recipe against a live pantry
function computeAllCoverage(recipes, pantry) {
  const pantrySet = buildPantrySet(pantry);
  return recipes.map(r => {
    if (!r.ingredients || r.ingredients.length === 0)
      return { ...r, missingCount: 0, missingIngredients: [], pantryScore: 100, pantryComplete: true };
    const missing = r.ingredients.filter(i => !ingInPantry(i.n, pantrySet)).map(i => i.n);
    const matchCount = r.ingredients.length - missing.length;
    return {
      ...r,
      missingCount: missing.length,
      missingIngredients: missing,
      pantryScore: Math.round((matchCount / r.ingredients.length) * 100),
      pantryComplete: missing.length === 0,
    };
  });
}

// summarizeCoverage: total + 0-missing counts keyed by meal type
function summarizeCoverage(coveredRecipes) {
  const total    = { breakfast:0, lunch:0, dinner:0, snack:0, all:0 };
  const complete = { breakfast:0, lunch:0, dinner:0, snack:0, all:0 };
  coveredRecipes.forEach(r => {
    const m = getMealType(r);
    total.all++; if (m in total) total[m]++;
    if (r.pantryComplete) { complete.all++; if (m in complete) complete[m]++; }
  });
  return { total, complete };
}

// computeIngredientImpact: rank every missing ingredient by recipe unlock count
function computeIngredientImpact(coveredRecipes) {
  const impact = {};
  coveredRecipes.forEach(r => {
    if (r.missingCount === 0) return;
    r.missingIngredients.forEach(ing => {
      const norm = normalizeIng(ing);
      if (!impact[norm]) impact[norm] = { name: ing, norm, recipeIds: new Set(), byMeal: {breakfast:0,lunch:0,dinner:0,snack:0} };
      impact[norm].recipeIds.add(r.id);
      const m = getMealType(r);
      if (m in impact[norm].byMeal) impact[norm].byMeal[m]++;
    });
  });
  return Object.values(impact)
    .map(i => ({ name: i.name, norm: i.norm, count: i.recipeIds.size, byMeal: i.byMeal, recipeIds: [...i.recipeIds] }))
    .sort((a, b) => b.count - a.count);
}

// greedyCoverageExpansion: minimal ingredient set to maximise 0-missing meals
function greedyCoverageExpansion(coveredRecipes, existingPantry, maxSuggestions = 15) {
  let remaining = coveredRecipes.filter(r => r.missingCount > 0);
  const addedNorms = new Set(existingPantry.map(p => normalizeIng(p.name)));
  const suggestions = [];
  while (remaining.length > 0 && suggestions.length < maxSuggestions) {
    const impact = {};
    remaining.forEach(r => {
      r.missingIngredients.forEach(ing => {
        const norm = normalizeIng(ing);
        if (addedNorms.has(norm)) return;
        if (!impact[norm]) impact[norm] = { name: ing, unlocks: new Set(), byMeal: {breakfast:0,lunch:0,dinner:0,snack:0} };
        impact[norm].unlocks.add(r.id);
        const m = getMealType(r);
        if (m in impact[norm].byMeal) impact[norm].byMeal[m]++;
      });
    });
    const ranked = Object.values(impact).sort((a, b) => b.unlocks.size - a.unlocks.size);
    if (!ranked.length) break;
    const best = ranked[0];
    suggestions.push({ name: best.name, unlocks: best.unlocks.size, byMeal: { ...best.byMeal } });
    addedNorms.add(normalizeIng(best.name));
    remaining = remaining.filter(r => !best.unlocks.has(r.id));
  }
  let cum = coveredRecipes.filter(r => r.missingCount === 0).length;
  suggestions.forEach(s => { cum += s.unlocks; s.cumTotal = cum; });
  return suggestions;
}

