// Helper: Derive meal type from recipe (based on ID ranges and keywords)
const getMealType = (recipe) => {
  // SINGLE SOURCE OF TRUTH: use recipe.meal field (set on all recipes in dataset).
  // All legacy recipes (IDs 1–131) were patched to include meal: field during Step 2
  // of the June 2026 stabilization pass. Hardcoded ID lists removed.
  if (recipe.meal) return recipe.meal;

  // Safety fallback: infer from title keywords if meal field is somehow absent,
  // then default to "dinner". Always log so missing field is detectable.
  const t = (recipe.title || "").toLowerCase();
  const BREAKFAST_KWS = ["pancake","oatmeal","smoothie","waffle","granola","porridge","frittata",
    "omelette","omelet","french toast","avocado toast","overnight oat","chia pudding","yogurt bowl"];
  const LUNCH_KWS = ["sandwich","wrap","salad","soup","bowl","taco","quesadilla","pita","ramen","pho"];
  for (const kw of BREAKFAST_KWS) if (t.includes(kw)) {
    console.warn(`[SmartChef] Recipe id:${recipe.id} "${recipe.title}" missing meal field — inferred: breakfast`);
    return "breakfast";
  }
  for (const kw of LUNCH_KWS) if (t.includes(kw)) {
    console.warn(`[SmartChef] Recipe id:${recipe.id} "${recipe.title}" missing meal field — inferred: lunch`);
    return "lunch";
  }
  console.warn(`[SmartChef] Recipe id:${recipe.id} "${recipe.title}" missing meal field — defaulting to: dinner`);
  return "dinner";
};

// CORE DISH DEDUPLICATION SYSTEM
// Compute canonical "core dish key" to prevent near-duplicate variants in same week

const computeCoreDishKey = (recipe) => {
  if(!recipe || !recipe.title) return '';
  
  let normalized = recipe.title
    .toLowerCase()
    .replace(/[.,!?]/g, '')
    .trim();
  
  // Remove filler words that don't change dish identity
  const fillerWords = [
    'one-pan', 'one pan', 'sheet pan', 'skillet', 'pan',
    'quick', 'easy', 'simple', 'classic', 'homestyle', 'style',
    'bowl', 'plate', 'weeknight', 'fluffy', 'savory', 'fresh'
  ];
  
  fillerWords.forEach(word => {
    const regex = new RegExp(`\\b${word}\\b`, 'g');
    normalized = normalized.replace(regex, '');
  });
  
  // NOTE: Cooking method words (roasted, baked, grilled, etc.) are intentionally
  // NOT stripped — "Roasted Chicken" and "Baked Chicken" are different dishes.
  // Stripping methods collapses distinct recipes with 1000+ recipe DB, causing under-variety.

  // Clean up whitespace
  normalized = normalized.replace(/\s+/g, ' ').trim();
  
  // Synonym mapping for known dish variants
  const synonymMap = {
    'shakshuka': 'shakshuka',
    'shakshouka': 'shakshuka',
    'chana masala': 'chickpea curry',
    'chole masala': 'chickpea curry',
    'aglio e olio': 'spaghetti aglio olio',
    'aglio olio': 'spaghetti aglio olio',
    'cacio e pepe': 'cacio pepe',
    'ratatouille': 'ratatouille',
    'frittata': 'frittata',
    'omelette': 'omelette',
    'omelet': 'omelette',
    'avocado toast': 'avocado toast',
  };
  
  // Apply synonym mapping
  for(const [variant, canonical] of Object.entries(synonymMap)) {
    if(normalized.includes(variant)) {
      normalized = canonical;
      break;
    }
  }
  
  return normalized;
};

// Compute ingredient signature for similarity checking
const computeIngredientSignature = (recipe) => {
  if(!recipe || !recipe.ingredients) return new Set();
  
  // Base ingredients to exclude (common pantry items)
  const baseIngredients = new Set([
    'salt', 'pepper', 'water', 'olive oil', 'oil',
    'onion', 'garlic', 'black pepper'
  ]);
  
  const signature = new Set();
  
  recipe.ingredients.forEach(ing => {
    const name = normalizeIng(ing.n);
    if(name && !baseIngredients.has(name)) {
      signature.add(name);
    }
  });
  
  return signature;
};

// Calculate Jaccard similarity between two sets
const jaccardSimilarity = (setA, setB) => {
  const intersection = new Set([...setA].filter(x => setB.has(x)));
  const union = new Set([...setA, ...setB]);
  
  if(union.size === 0) return 0;
  return intersection.size / union.size;
};

// Check if two recipes are the same core dish
const isSameCoreDish = (recipeA, recipeB) => {
  // Check 1: Same core dish key
  const keyA = computeCoreDishKey(recipeA);
  const keyB = computeCoreDishKey(recipeB);
  
  if(keyA && keyB && keyA === keyB) {
    console.debug(`DEDUPED core dish: "${recipeB.title}" grouped as "${keyB}" (title match with "${recipeA.title}")`);
    return true;
  }
  
  // Check 2: High ingredient similarity + same/compatible cuisine
  const sigA = computeIngredientSignature(recipeA);
  const sigB = computeIngredientSignature(recipeB);
  const similarity = jaccardSimilarity(sigA, sigB);
  
  const cuisineCompatible = recipeA.cuisine === recipeB.cuisine ||
    (recipeA.cuisine && recipeB.cuisine && 
     (recipeA.cuisine.includes('Italian') && recipeB.cuisine.includes('Italian')) ||
     (recipeA.cuisine.includes('Mediterranean') && recipeB.cuisine.includes('Mediterranean')) ||
     (recipeA.cuisine.includes('Asian') && recipeB.cuisine.includes('Asian')));
  
  if(similarity >= 0.82 && cuisineCompatible && sigA.size >= 5) {
    console.debug(`DEDUPED core dish: "${recipeB.title}" grouped with "${recipeA.title}" (similarity: ${similarity.toFixed(2)}, cuisine: ${recipeA.cuisine})`);
    return true;
  }
  
  return false;
};

// DIETARY COMPLIANCE FUNCTION - SHARED EVERYWHERE
// ── Health scoring heuristic (used when prefs.dietary includes "Healthy") ──────
// Returns a score: positive = healthier, negative = less healthy.
// Does NOT ban recipes — just sorts them. Max range ~ ±6.
const getHealthScore = (recipe) => {
  if (!recipe) return 0;
  const title = (recipe.title || '').toLowerCase();
  const ings  = (recipe.ingredients || []).map(i => (i.n || '').toLowerCase()).join(' ');
  const text   = title + ' ' + ings;
  let score = 0;
  // ── Penalise ────────────────────────────────────────────────────────────────
  const SUGAR_TERMS   = /sugar|brown sugar|honey|maple syrup|condensed milk|sweetened|syrup|chocolate|candy|sprinkles|caramel|frosting|icing/;
  const FRIED_TERMS   = /deep.?fr(y|ied|ying)|deep fr|battered and fried|tempura/;
  const HEAVY_DAIRY   = /heavy cream|double cream|full.fat cream|large amount.*butter/;
  const JUNK_TERMS    = /cookie|cookies|cake|donut|donuts|ice cream|soda|chips|crackers|pastry|croissant|brownie|muffin/;
  const HEAVY_CHEESE  = /cheddar.*\d{2,}g|mozzarella.*\d{2,}g|parmesan.*\d{2,}g/;
  if (SUGAR_TERMS.test(text))  score -= 2;
  if (FRIED_TERMS.test(text))  score -= 2;
  if (HEAVY_DAIRY.test(text))  score -= 1;
  if (JUNK_TERMS.test(text))   score -= 2;
  if (HEAVY_CHEESE.test(ings)) score -= 1;
  // Extra penalty for recipes labelled "fried" in the title
  if (/fried/.test(title) && !/pan.?fried|stir.?fried/.test(title)) score -= 1;
  // ── Reward ──────────────────────────────────────────────────────────────────
  const HEALTHY_TERMS = /salad|lentil|chickpea|quinoa|brown rice|oats|oatmeal|vegetable|broccoli|spinach|kale|zucchini|asparagus|legume|tofu|tempeh|bean|edamame|avocado|baked|steamed|grilled|poached|whole grain|wholegrain/;
  if (HEALTHY_TERMS.test(text)) score += 2;
  if ((recipe.dietary||[]).includes('Vegan'))       score += 1;
  if ((recipe.dietary||[]).includes('Vegetarian'))  score += 1;
  if ((recipe.dietary||[]).includes('Gluten-free')) score += 0.5;
  return score;
};

const isRecipeAllowedForUser = (recipe, prefs) => {
  if(!recipe || !prefs) return true;
  const dietary = prefs.dietary || [];
  // dietary is an array with 0 or 1 element (single-select mode):
  // [] = Omnivore (no restrictions)
  // ["Pescatarian"] = fish OK, no meat
  // ["Vegetarian"]  = no meat, no fish
  // ["Vegan"]       = no meat, fish, shellfish, dairy
  // ["Kosher"]      = kosher_safe filter
  
  // Pescatarian: allow fish/shellfish, exclude land meat only
  if(dietary.includes("Pescatarian")) {
    if(recipe.contains_meat) return false;
    // Fish and shellfish ARE allowed — do not block them
  }
  
  // Vegetarian: exclude all meat AND fish/shellfish
  if(dietary.includes("Vegetarian")) {
    if(recipe.contains_meat || recipe.contains_fish || recipe.contains_shellfish) return false;
  }
  
  // Vegan: exclude all animal products
  if(dietary.includes("Vegan")) {
    if(recipe.contains_meat || recipe.contains_fish || recipe.contains_shellfish || recipe.contains_dairy) return false;
  }
  
  // Kosher: no shellfish, no pork, no meat+dairy mix, respect kosher_safe flag
  if(dietary.includes("Kosher")) {
    if(recipe.contains_shellfish) return false;
    const hasPork = recipe.ingredients?.some(i => {
      const n = i.n.toLowerCase();
      return n.includes("pork") || n.includes("bacon") || n.includes("ham");
    });
    if(hasPork) return false;
    if(recipe.contains_meat && recipe.contains_dairy) return false;
    if(recipe.kosher_risk) return false;
    if(recipe.kosher_safe === false) return false;
  }
  
  // Gluten-free check
  if(dietary.includes("Gluten-free")) {
    if(!recipe.dietary?.includes("Gluten-free")) {
      const hasGluten = recipe.ingredients?.some(ing=>{
        const n=ing.n.toLowerCase();
        return n.includes("pasta")||n.includes("bread")||n.includes("flour")||n.includes("pita")||n.includes("naan")||n.includes("soy sauce");
      });
      if(hasGluten) return false;
    }
  }
  
  return true; // Passed all checks
};

