const getIcon = (name, cat) => {
  const n = name.toLowerCase();
  // Check specific ingredient overrides first
  for (const [k,v] of Object.entries(ING_ICON)) { 
    if(n.includes(k)) return v; 
  }
  // Fall back to category icon (NEVER default to meat)
  return CE[cat] || "📦";
};
