const DEFKNOW = { life:"See packaging",stor:"Store cool and dry, or refrigerate after opening.",best:"Versatile cooking ingredient",days:14 };

// Helper: get estimated shelf life in days for auto-expiry
const getShelfLifeDays = (name) => {
  // Direct match
  const match = INGKNOW[name];
  if(match && match.days) return match.days;
  // Fuzzy match: try lowercase key lookup
  const lower = name.toLowerCase().trim();
  for(const [key, val] of Object.entries(INGKNOW)) {
    if(key.toLowerCase() === lower) return val.days;
    // Partial match: "cherry tomatoes" → "Tomatoes"
    if(lower.includes(key.toLowerCase()) || key.toLowerCase().includes(lower)) return val.days;
  }
  // Category-based defaults
  const cat = autoDetect(name);
  const catDefaults = {
    "Produce": 7, "Protein": 3, "Dairy": 14, "Frozen": 90,
    "Pantry": 180, "Spices": 365, "Sauces": 90, "Other": 14
  };
  return catDefaults[cat] || 14;
};

// CRITICAL: Dietary compliance checker (used everywhere - auto-plan, replace, Chef AI, meal prep)

/* ── DIETARY COMPLIANCE CHECKER (STRICT) ── */

// Calculate pantry match score (0-100)
const getPantryMatchScore = (recipe, pantryItems) => {
  if(!recipe.ingredients || recipe.ingredients.length === 0) return 0;
  const pantryNames = new Set(pantryItems.map(i => i.name.toLowerCase()));
  const matched = recipe.ingredients.filter(ing => {
    const ingName = ing.n.toLowerCase();
    return Array.from(pantryNames).some(p => ingName.includes(p) || p.includes(ingName));
  });
  return Math.round((matched.length / recipe.ingredients.length) * 100);
};

// Canonical ingredient normalization map
const CANONICAL_MAP = {
  // Pasta variants → pasta
  "spaghetti":"pasta","penne":"pasta","fettuccine":"pasta","linguine":"pasta","rigatoni":"pasta","fusilli":"pasta","macaroni":"pasta","lasagna sheets":"pasta","lasagne":"pasta","tagliatelle":"pasta","angel hair":"pasta","bow tie":"pasta","farfalle":"pasta","shells":"pasta","conchiglie":"pasta","orzo":"pasta","ziti":"pasta",
  // Rice variants → rice
  "basmati rice":"rice","jasmine rice":"rice","brown rice":"rice","white rice":"rice","arborio rice":"rice","wild rice":"rice","sushi rice":"rice",
  // Tomatoes → tomatoes
  "cherry tomatoes":"tomatoes","grape tomatoes":"tomatoes","plum tomatoes":"tomatoes","roma tomatoes":"tomatoes","beefsteak tomatoes":"tomatoes",
  "canned tomatoes":"tomatoes","diced tomatoes":"tomatoes","crushed tomatoes":"tomatoes","whole tomatoes":"tomatoes","tomato":"tomatoes",
  // Peppers → bell pepper
  "red pepper":"bell pepper","green pepper":"bell pepper","yellow pepper":"bell pepper","orange pepper":"bell pepper","sweet pepper":"bell pepper",
  // Onions → onion
  "red onion":"onion","white onion":"onion","yellow onion":"onion","brown onion":"onion","sweet onion":"onion",
  // Milk → milk
  "whole milk":"milk","skim milk":"milk","2% milk":"milk","1% milk":"milk","fat-free milk":"milk",
  // Bread → bread
  "white bread":"bread","whole wheat bread":"bread","brown bread":"bread","sourdough":"bread","baguette":"bread","ciabatta":"bread","sandwich bread":"bread",
  // Beans
  "black beans":"beans","kidney beans":"beans","pinto beans":"beans","white beans":"beans","cannellini beans":"beans","navy beans":"beans","chickpeas":"beans","garbanzo beans":"beans",
};

const getCanonical = name => {
  const n = name.toLowerCase().trim();
  return CANONICAL_MAP[n] || name;
};

const getVariant = (name, canonical) => {
  const n = name.toLowerCase().trim();
  if(CANONICAL_MAP[n] === canonical.toLowerCase()) return name;
  return null;
};

/* ── DIETARY COMPLIANCE CHECKER ── */

/* ─────────────────────────────────────────────
   DIETARY COMPLIANCE CHECKER (CRITICAL)
───────────────────────────────────────────── */

/* ── improved ingredient detection ── */
const autoDetect = name => {
  const n = name.toLowerCase();
  // Produce (veg + fruit) — checked BEFORE protein to catch eggplant, avocado etc.
  if (["tomato","onion","garlic","spinach","pepper","zucchini","broccoli","carrot","cucumber","mushroom","leek","celery","eggplant","aubergine","avocado","lemon","lime","apple","banana","berry","berries","cherry","orange","grape","mango","peach","plum","pear","pineapple","melon","kiwi","lettuce","kale","cabbage","cauliflower","pumpkin","squash","beet","radish","turnip","artichoke","asparagus","corn","pea","herb","parsley","basil","cilantro","coriander leaf","dill","mint","chive","green onion","spring onion","scallion"].some(v=>n.includes(v))) return "Produce";
  // Protein
  if (["chicken","turkey","duck","beef","pork","lamb","veal","steak","mince","ground meat","tuna","salmon","cod","tilapia","shrimp","prawn","fish","seafood","tofu","tempeh","seitan","chickpea","lentil","bean","legume"].some(v=>n.includes(v))) return "Protein";
  // Eggs — produce-adjacent but keep Protein
  if (n==="egg"||n==="eggs"||n.startsWith("egg")) return "Protein";
  // Dairy
  if (["butter","milk","yogurt","feta","parmesan","mozzarella","cream","cheddar","cheese","ricotta","brie","gouda","halloumi","lactose","whey"].some(v=>n.includes(v))) return "Dairy";
  // Frozen
  if (n.startsWith("frozen")||["frozen peas","frozen corn","frozen fish","frozen shrimp","frozen spinach"].some(v=>n.includes(v))) return "Frozen";
  // Spices/herbs (dried)
  if (["cumin","paprika","chili flake","turmeric","coriander","oregano","thyme","cinnamon","pepper","cardamom","clove","nutmeg","allspice","star anise","bay leaf","rosemary","sage","tarragon","za'atar","sumac","harissa","garam masala","curry powder","mixed spice","spice","seasoning"].some(v=>n.includes(v))) return "Spices";
  // Sauces/condiments
  if (["sauce","soy","tahini","miso","hot sauce","worcestershire","vinegar","ketchup","mustard","mayo","mayonnaise","pesto","hummus","chutney","relish","jam","honey","syrup","oil","olive oil","sesame oil","fish sauce","oyster sauce","hoisin","sriracha","tabasco"].some(v=>n.includes(v))) return "Sauces";
  // Pantry staples
  if (["pasta","noodle","rice","flour","sugar","breadcrumb","oat","quinoa","couscous","bulgur","lentil","grain","cereal","crackers","biscuit","bread","wrap","tortilla","pita","stock","broth","coconut milk","canned","tin","jar","baking powder","baking soda","yeast","salt","vinegar"].some(v=>n.includes(v))) return "Pantry";
  return "Pantry";
};

// Map category-header synonyms from pasted text onto our categories
const CAT_HEADER_MAP = {
  // Produce variants
  "fruits and vegetables":"Produce","fruits & vegetables":"Produce","fruit and vegetables":"Produce","fruit & vegetables":"Produce",
  "fruit and veg":"Produce","fruits and veg":"Produce","fruit & veg":"Produce","fruits & veg":"Produce",
  "vegetables":"Produce","fruits":"Produce","veggies":"Produce","fresh vegetables":"Produce","fresh fruits":"Produce",
  "produce":"Produce","fresh produce":"Produce","fresh veg":"Produce","veg":"Produce",
  // Protein variants
  "protein":"Protein","proteins":"Protein","meat":"Protein","meats":"Protein","poultry":"Protein","fish":"Protein","seafood":"Protein",
  "meat and fish":"Protein","meat & fish":"Protein","meat and poultry":"Protein","meat & poultry":"Protein",
  "fish and seafood":"Protein","fish & seafood":"Protein",
  // Legumes (→ Protein category)
  "legumes":"Protein","legume":"Protein","beans and legumes":"Protein","beans & legumes":"Protein","pulses":"Protein",
  // Dairy variants
  "dairy":"Dairy","dairy products":"Dairy","dairy & eggs":"Dairy","dairy and eggs":"Dairy","cheese":"Dairy","cheeses":"Dairy",
  "milk and cheese":"Dairy","milk & cheese":"Dairy",
  // Grains / Pantry
  "grains":"Pantry","grain":"Pantry","grains and cereals":"Pantry","grains & cereals":"Pantry","cereals":"Pantry",
  "pantry":"Pantry","pantry staples":"Pantry","pantry items":"Pantry","dry goods":"Pantry","staples":"Pantry",
  "canned":"Pantry","canned goods":"Pantry","tinned":"Pantry","tinned goods":"Pantry",
  "baking":"Pantry","baking supplies":"Pantry","baking essentials":"Pantry",
  // Nuts & seeds
  "nuts":"Pantry","seeds":"Pantry","nuts and seeds":"Pantry","nuts & seeds":"Pantry",
  // Frozen
  "frozen":"Frozen","freezer":"Frozen","frozen foods":"Frozen","frozen items":"Frozen",
  // Spices
  "spices":"Spices","herbs":"Spices","spices and herbs":"Spices","herbs and spices":"Spices",
  "spices & herbs":"Spices","herbs & spices":"Spices","seasonings":"Spices","seasoning":"Spices",
  "dried herbs":"Spices","dried spices":"Spices",
  // Sauces
  "sauces":"Sauces","condiments":"Sauces","condiment":"Sauces","oils":"Sauces",
  "sauces and condiments":"Sauces","sauces & condiments":"Sauces","dressings":"Sauces",
  "oils and vinegars":"Sauces","oils & vinegars":"Sauces",
  // Beverages (→ Other)
  "beverages":"Other","drinks":"Other","beverages and drinks":"Other",
  // Other
  "other":"Other","miscellaneous":"Other","misc":"Other","snacks":"Other",
};

// Non-ingredient patterns: category headers that might appear WITHOUT colons
// These are never actual ingredients — they should be detected and skipped
const NON_INGREDIENT_PATTERNS = [
  // Exact matches (lowercased)
  "fruits and vegetables","fruits & vegetables","fruit and vegetables","fruit & vegetables",
  "fruits and veg","fruits & veg","fresh produce","fresh vegetables","fresh fruits",
  "meat and fish","meat & fish","meat and poultry","meat & poultry","fish and seafood","fish & seafood",
  "beans and legumes","beans & legumes","dairy products","dairy and eggs","dairy & eggs",
  "grains and cereals","grains & cereals","nuts and seeds","nuts & seeds",
  "pantry staples","pantry items","dry goods","canned goods","tinned goods",
  "frozen foods","frozen items","spices and herbs","herbs and spices","spices & herbs","herbs & spices",
  "dried herbs","dried spices","sauces and condiments","sauces & condiments","oils and vinegars","oils & vinegars",
  "baking supplies","baking essentials",
  // Single-word category names that are NOT ingredients
  "vegetables","veggies","fruits","produce","proteins","legumes","legume","pulses",
  "grains","cereals","staples","condiments","seasonings","miscellaneous","snacks",
  "beverages","drinks","misc",
];

const isNonIngredient = (name) => {
  const n = name.toLowerCase().trim();
  // Check exact match against non-ingredient patterns
  if(NON_INGREDIENT_PATTERNS.includes(n)) return true;
  // Check against CAT_HEADER_MAP keys (without colon)
  if(CAT_HEADER_MAP[n]) return true;
  // Reject very short items or pure numbers
  if(n.length < 2 || /^\d+$/.test(n)) return true;
  return false;
};

// Noise phrases to strip from ingredient names
const NOISE = [/\band many like (this|these)\b/gi,/\betc\.?\b/gi,/\band more\b/gi,/\blike this\b/gi,/\(.*?\)/g,/[…\.]{2,}/g,/^\s*[-•*–]\s*/,/\s{2,}/g];

const cleanName = raw => {
  let s = raw.trim();
  NOISE.forEach(r => { s = s.replace(r, " "); });
  return s.trim().replace(/[,;]+$/, "").trim();
};

const smartParseList = rawText => {
  const lines = rawText.split(/\n/).map(l => l.trim()).filter(Boolean);
  const results = [];
  let currentCat = null; // category override from header

  const addItem = (name, catOverride) => {
    const n = cleanName(name);
    if (!n || n.length < 2) return;
    // Skip category headers and non-ingredient items (e.g. "Fruits & Vegetables", "Legumes")
    if (isNonIngredient(n)) {
      // But set the category context if it maps to one
      const mapped = CAT_HEADER_MAP[n.toLowerCase().trim()];
      if(mapped) currentCat = mapped;
      return;
    }
    const cat = catOverride || autoDetect(n);
    const shelfDays = getShelfLifeDays(n);
    const expiry = new Date();
    expiry.setDate(expiry.getDate() + shelfDays);
    results.push({ id: Date.now() + Math.random(), name: n, category: cat, quantity: 1, unit: "pcs", emoji: CE[cat] || "📦", expiry: expiry.toISOString().split('T')[0] });
  };

  lines.forEach(line => {
    // Strip leading bullets
    const stripped = line.replace(/^[-•*–]\s*/, "").trim();

    // Check for "Category: item1, item2" or "Category: item1\nitem2"
    const colonIdx = stripped.indexOf(":");
    if (colonIdx > 0 && colonIdx < 40) {
      const potentialHeader = stripped.slice(0, colonIdx).toLowerCase().trim();
      const mapped = CAT_HEADER_MAP[potentialHeader];
      const rest = stripped.slice(colonIdx + 1).trim();

      if (mapped) {
        currentCat = mapped;
        if (rest) {
          // Items listed after colon on same line
          rest.split(/,/).forEach(part => addItem(part, mapped));
        }
        // else: next lines will use currentCat
        return;
      }
    }

    // Check for category header WITHOUT colon (e.g., "Fruits & Vegetables" on its own line)
    const headerCheck = stripped.toLowerCase().trim();
    if (CAT_HEADER_MAP[headerCheck]) {
      currentCat = CAT_HEADER_MAP[headerCheck];
      return; // Don't add as ingredient
    }

    // Not a header — treat as item(s). Could be comma-separated on one line.
    if (stripped.includes(",")) {
      stripped.split(",").forEach(part => addItem(part, currentCat));
    } else {
      addItem(stripped, currentCat);
    }
  });

  // Also handle a single-line paste with no newlines (pure comma-separated)
  if (results.length === 0 && rawText.includes(",")) {
    rawText.split(",").forEach(part => addItem(part, null));
  }

  return results;
};

/* ── ERROR BOUNDARY ── */
class RecipeErrorBoundary extends React.Component {
  constructor(props) { super(props); this.state = { hasError: false, error: null }; }
  static getDerivedStateFromError(error) { return { hasError: true, error }; }
  componentDidCatch(error, info) { console.error('[SmartChef] RecipeDetail crash:', error, info); }
  render() {
    if (this.state.hasError) {
      return (
        <div style={{minHeight:'100vh',background:'var(--cream)',display:'flex',flexDirection:'column',alignItems:'center',justifyContent:'center',fontFamily:'var(--fb)',gap:16,padding:32}}>
          <style>{S}</style>
          <div style={{fontSize:48}}>🍳</div>
          <div style={{fontSize:20,fontWeight:700,color:'var(--ch)'}}>Recipe couldn't load</div>
          <div style={{fontSize:14,color:'var(--mu)',maxWidth:340,textAlign:'center'}}>
            Something went wrong displaying this recipe. This has been logged.
          </div>
          <button className="btn btn-p" onClick={()=>{this.setState({hasError:false,error:null});this.props.onBack?.();}}>
            ← Go back
          </button>
        </div>
      );
    }
    return this.props.children;
  }
}

