                    <div key={f} style={{display:"flex",alignItems:"center",gap:8,fontSize:13,color:locked?"var(--mu)":"var(--ch)"}}><span style={{color:locked?"var(--bor)":"var(--sage)",fontWeight:700}}>{locked?"✗":"✓"}</span>{f}</div>
